import api from './api';

export interface FoodSpot {
	id: string;
	name: string;
	category: string;
	distance: number;
	price_range: string;
	rating: number;
	open_now: boolean;
	address: string;
	phone: string;
	latitude: number;
	longitude: number;
}

export const foodService = {
	async getFoodSpots(
		latitude: number = 35.2271,
		longitude: number = -80.8431,
		radius: number = 5000
	): Promise<FoodSpot[]> {
		try {
			console.log('Making request to: /api/food');
			const response = await api.get('/api/food/', {
				params: { latitude, longitude, radius },
			});
			console.log('Response received:', response);
			console.log('Response data:', response.data);
			return response.data.spots || [];
		} catch (error) {
			console.error('Failed to get food spots:', error);
			throw error;
		}
	},
};
